function useCountUp(end: number, dur = 2000) { const [c,setC]=useState(0); const [s,setS]=useState(false); useEffect(()=>{ if(s)return; setS(true); let v=0; const inc=end/(dur/16); const t=setInterval(()=>{ v+=inc; if(v>=end){setC(end);clearInterval(t);} else setC(Math.floor(v));},16); return()=>clearInterval(t); },[end,dur,s]); return c; }

function Navbar(){const[scrolled,setScrolled]=useState(false);const[mo,setMo]=useState(false);useEffect(()=>{const h=()=>setScrolled(window.scrollY>20);window.addEventListener("scroll",h);return()=>window.removeEventListener("scroll",h);},[]);return(<nav style={{position:"fixed",top:0,left:0,right:0,zIndex:1000,background:scrolled?"rgba(9,9,11,0.85)":"transparent",backdropFilter:scrolled?"blur(20px)":"none",borderBottom:scrolled?"1px solid var(--border-subtle)":"none",transition:"all 0.3s ease",padding:"0 24px"}}><div style={{maxWidth:1200,margin:"0 auto",display:"flex",alignItems:"center",justifyContent:"space-between",height:72}}><a href="/" style={{display:"flex",alignItems:"center",gap:10,textDecoration:"none"}}><div style={{width:36,height:36,borderRadius:10,background:"var(--gradient-primary)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,fontWeight:800,color:"white"}}>E</div><span style={{fontSize:18,fontWeight:700,color:"var(--text-primary)"}}>EcomRevHub</span></a><div style={{display:"flex",alignItems:"center",gap:32}} className="nav-links-desktop">{["Features","Demo","Calculator","Pricing","FAQ"].map(i=><a key={i} href={`#${i.toLowerCase()}`} style={{color:"var(--text-secondary)",textDecoration:"none",fontSize:14,fontWeight:500}}>{i}</a>)}</div><div style={{display:"flex",alignItems:"center",gap:12}}><a href="/auth/login" style={{color:"var(--text-secondary)",textDecoration:"none",fontSize:14,fontWeight:500,padding:"8px 16px"}}>Log in</a><a href="/auth/register" className="btn-primary" style={{padding:"10px 22px",fontSize:14}}>Start Free Trial</a><button onClick={()=>setMo(!mo)} style={{display:"none",background:"none",border:"none",color:"var(--text-primary)",cursor:"pointer",padding:4}} className="mobile-menu-btn">{mo?<Icons.X/>:<Icons.Menu/>}</button></div></div>{mo&&<div style={{padding:"16px 24px 24px",background:"rgba(9,9,11,0.95)",backdropFilter:"blur(20px)",borderTop:"1px solid var(--border-subtle)",display:"flex",flexDirection:"column",gap:16}}>{["Features","Demo","Calculator","Pricing","FAQ"].map(i=><a key={i} href={`#${i.toLowerCase()}`} onClick={()=>setMo(false)} style={{color:"var(--text-secondary)",textDecoration:"none",fontSize:16,fontWeight:500}}>{i}</a>)}</div>}<style>{`@media(max-width:768px){.nav-links-desktop{display:none !important;}.mobile-menu-btn{display:block !important;}}`}</style></nav>);}

function Hero(){const b=useCountUp(2000,2500);return(<section style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",textAlign:"center",padding:"120px 24px 80px",position:"relative",overflow:"hidden"}}><div style={{position:"absolute",inset:0,background:"var(--gradient-hero)",pointerEvents:"none"}}/><div style={{position:"absolute",inset:0,background:"var(--gradient-hero-2)",pointerEvents:"none"}}/><div className="grid-bg" style={{position:"absolute",inset:0,pointerEvents:"none"}}/><div style={{position:"absolute",top:"15%",left:"10%",width:300,height:300,borderRadius:"50%",background:"radial-gradient(circle, rgba(99,102,241,0.08), transparent 70%)",animation:"float 8s ease-in-out infinite",pointerEvents:"none"}}/><div style={{position:"relative",zIndex:1,maxWidth:800}}><div className="section-label animate-fade-in"><Icons.Zap/> Your One-Stop Shop for E-Commerce Growth</div><h1 style={{fontSize:"clamp(40px,6vw,72px)",fontWeight:800,lineHeight:1.05,marginBottom:24,letterSpacing:"-0.03em"}} className="animate-fade-in-up">Grow Your Revenue with <span className="gradient-text">AI-Powered</span> Intelligence</h1><p style={{fontSize:"clamp(16px,2vw,20px)",color:"var(--text-secondary)",maxWidth:580,margin:"0 auto 40px",lineHeight:1.7}} className="animate-fade-in-up">Build it, launch it, grow it — all in one place. Complete AI platform with autonomous agents, store builder, analytics, marketing, and dropshipping automation.</p><div style={{display:"flex",gap:16,justifyContent:"center",flexWrap:"wrap",marginBottom:40}} className="animate-fade-in-up"><a href="/auth/register" className="btn-primary" style={{fontSize:17,padding:"16px 36px"}}><Icons.Rocket/> Analyze My Store Free</a><a href="#demo" className="btn-secondary" style={{fontSize:17,padding:"16px 36px"}}>Try the Calculator</a></div><div style={{display:"flex",gap:32,justifyContent:"center",flexWrap:"wrap",fontSize:14,color:"var(--text-tertiary)"}} className="animate-fade-in">{["Free 14-day trial","No credit card required","Setup in 5 minutes"].map((t,i)=><span key={i} style={{display:"flex",alignItems:"center",gap:6}}><span style={{color:"var(--accent-green)"}}><Icons.Check/></span> {t}</span>)}</div></div><div style={{position:"relative",zIndex:1,marginTop:60,display:"flex",gap:48,flexWrap:"wrap",justifyContent:"center"}} className="animate-fade-in-up">{[{value:"Early Access",label:"Now Open"},{value:"4.9/5",label:"Beta Rating"},{value:"14+",label:"AI Features Live"},{value:"Growing",label:"AI Actions Daily"}].map((s,i)=><div key={i} style={{textAlign:"center"}}><div style={{fontSize:28,fontWeight:700,fontFamily:"'Space Mono', monospace"}}>{s.value}</div><div style={{fontSize:13,color:"var(--text-tertiary)",marginTop:4}}>{s.label}</div></div>)}</div><div className="glass-card animate-fade-in-up" style={{marginTop:60,padding:24,maxWidth:700,width:"100%",position:"relative",zIndex:1}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><span style={{fontSize:14,fontWeight:600}}>Live Revenue Trend</span><span style={{fontSize:12,color:"var(--text-tertiary)"}}>Last 12 weeks</span></div><div style={{display:"flex",alignItems:"flex-end",gap:6,height:120}}>{[35,42,38,55,48,62,58,72,68,85,78,92].map((h,i)=><div key={i} style={{flex:1,height:`${h}%`,borderRadius:"4px 4px 0 0",background:i>=10?"var(--gradient-primary)":`rgba(99,102,241,${0.2+i*0.06})`,transition:"height 0.5s ease"}}/>)}</div></div></section>);}

function FeatureCarousel(){const[active,setActive]=useState(0);const[progress,setProgress]=useState(0);const ref=useRef<ReturnType<typeof setInterval>|null>(null);const D=4000;const features=[{icon:<Icons.Bot/>,title:"AI Autonomous Agents",desc:"A team of 6 AI agents that run your business 24/7 on full autopilot",stat:"24/7",statLabel:"Autonomous Execution",color:"#6366f1"},{icon:<Icons.Wand/>,title:"AI App Builder",desc:"Describe your store and watch AI build it in seconds",stat:"10s",statLabel:"Prompt to Live Site",color:"#8b5cf6"},{icon:<Icons.Store/>,title:"DFY Store Builder",desc:"We design, build, and launch your store — done for you",stat:"24hr",statLabel:"Store Launch Time",color:"#ec4899"},{icon:<Icons.BarChart/>,title:"AI Analytics & Insights",desc:"Deep revenue analytics and AI-generated business insights",stat:"+23%",statLabel:"Avg Revenue Increase",color:"#06b6d4"},{icon:<Icons.Mail/>,title:"Email & SMS Marketing",desc:"AI-crafted flows that convert browsers into buyers",stat:"3.2x",statLabel:"Higher Open Rates",color:"#22c55e"},{icon:<Icons.Tag/>,title:"Product Optimization",desc:"AI rewrites titles, descriptions, and SEO tags",stat:"+40%",statLabel:"Click-Through Rate",color:"#f97316"},{icon:<Icons.Megaphone/>,title:"AI Ad Campaign Manager",desc:"Launch and optimize ads across Meta, Google, TikTok",stat:"4.8x",statLabel:"Avg ROAS",color:"#eab308"},{icon:<Icons.Headphones/>,title:"AI Customer Support",desc:"Instant ticket resolution with human handoff",stat:"<30s",statLabel:"Avg Response Time",color:"#14b8a6"},{icon:<Icons.Search/>,title:"Store Audit & Crawling",desc:"Comprehensive SEO, UX, and competitor analysis",stat:"200+",statLabel:"Audit Checkpoints",color:"#f43f5e"},{icon:<Icons.Lightbulb/>,title:"Smart Recommendations",desc:"Actions ranked by revenue impact and effort",stat:"ROI",statLabel:"Ranked Priorities",color:"#a855f7"},{icon:<Icons.Truck/>,title:"AI Dropshipping Engine",desc:"Auto-import products, sync inventory, automate fulfillment",stat:"100%",statLabel:"Automated",color:"#f97316"},{icon:<Icons.DollarSign/>,title:"Revenue Calculator",desc:"See projected growth across all channels",stat:"5x",statLabel:"Revenue Channels",color:"#22c55e"},{icon:<Icons.Shield/>,title:"CRM & Customer Management",desc:"Track customers, segment audiences, personalize at scale",stat:"360°",statLabel:"Customer View",color:"#6366f1"},{icon:<Icons.Crown/>,title:"White-Label Solution",desc:"Rebrand and resell with full API access",stat:"∞",statLabel:"Scalability",color:"#8b5cf6"}];const startTimer=useCallback(()=>{if(ref.current)clearInterval(ref.current);setProgress(0);const st=Date.now();ref.current=setInterval(()=>{const e=Date.now()-st;const p=Math.min((e/D)*100,100);setProgress(p);if(e>=D){setActive(prev=>(prev+1)%features.length);if(ref.current)clearInterval(ref.current);}},30);},[features.length]);useEffect(()=>{startTimer();return()=>{if(ref.current)clearInterval(ref.current);};},[active,startTimer]);const goTo=(i:number)=>{if(ref.current)clearInterval(ref.current);setActive(i);};const f=features[active];return(<section className="section" style={{textAlign:"center",padding:"60px 24px 80px"}}><div className="container" style={{maxWidth:700}}><div style={{fontSize:14,color:"var(--text-tertiary)",marginBottom:32,fontFamily:"'Space Mono', monospace"}}>{active+1} / {features.length} Features</div><div style={{width:88,height:88,borderRadius:22,margin:"0 auto 28px",background:`linear-gradient(135deg, ${f.color}33, ${f.color}11)`,border:`1px solid ${f.color}44`,display:"flex",alignItems:"center",justifyContent:"center",color:f.color,fontSize:36,transition:"all 0.4s ease",boxShadow:`0 0 40px ${f.color}22`}}>{f.icon}</div><h3 style={{fontSize:"clamp(28px,4vw,42px)",fontWeight:800,marginBottom:12,letterSpacing:"-0.02em"}}>{f.title}</h3><p style={{fontSize:18,color:"var(--text-secondary)",maxWidth:500,margin:"0 auto 28px",lineHeight:1.6}}>{f.desc}</p><div style={{display:"inline-flex",alignItems:"center",gap:12,padding:"12px 28px",borderRadius:100,background:"var(--bg-tertiary)",border:"1px solid var(--border-subtle)"}}><span style={{fontSize:28,fontWeight:800,fontFamily:"'Space Mono', monospace",color:f.color}}>{f.stat}</span><span style={{fontSize:14,color:"var(--text-secondary)"}}>{f.statLabel}</span></div><div style={{height:3,background:"var(--bg-elevated)",borderRadius:2,margin:"32px auto 20px",maxWidth:400,overflow:"hidden"}}><div style={{height:"100%",borderRadius:2,background:`linear-gradient(90deg, ${f.color}, #ec4899)`,width:`${progress}%`,transition:"width 0.03s linear"}}/></div><div style={{display:"flex",justifyContent:"center",gap:6,flexWrap:"wrap"}}>{features.map((_,i)=><button key={i} onClick={()=>goTo(i)} style={{width:i===active?24:8,height:8,borderRadius:4,border:"none",cursor:"pointer",background:i===active?f.color:"var(--bg-elevated)",transition:"all 0.3s ease"}}/>)}</div></div></section>);}

function SocialProof(){return(<section style={{padding:"40px 24px",textAlign:"center"}}><div className="container" style={{display:"flex",justifyContent:"center",gap:48,flexWrap:"wrap"}}>{[{value:"Early Access",label:"Platform Status"},{value:"4.9/5",label:"Beta User Rating"},{value:"14+",label:"AI Modules Live"},{value:"100%",label:"Uptime SLA Target"}].map((s,i)=><div key={i} style={{textAlign:"center"}}><div style={{fontSize:32,fontWeight:800,fontFamily:"'Space Mono', monospace"}} className="gradient-text">{s.value}</div><div style={{fontSize:13,color:"var(--text-tertiary)",marginTop:4}}>{s.label}</div></div>)}</div></section>);}

function AIModules(){const modules=[{icon:<Icons.Bot/>,title:"AI Autonomous Agents",desc:"A team of 6 AI agents — CEO, Growth Manager, Engineer, Marketing, Support & Ad Manager — that run your business 24/7.",stat:"24/7 autonomous execution",badge:"new"},{icon:<Icons.Code/>,title:"AI App Builder",desc:"Describe your store in plain English and watch AI generate a complete, production-ready e-commerce site.",stat:"Prompt → Live site in seconds",badge:"new"},{icon:<Icons.BarChart/>,title:"AI Analytics & Insights",desc:"Deep revenue analytics, profit scoring, and AI-generated insights that show exactly where your money is going.",stat:"+23% avg revenue increase"},{icon:<Icons.Mail/>,title:"Email & SMS Marketing",desc:"AI-crafted email flows, campaigns, and SMS automation that convert browsers into buyers automatically.",stat:"3.2x higher open rates"},{icon:<Icons.Tag/>,title:"Product Optimization",desc:"AI rewrites titles, descriptions, and SEO tags to maximize conversions and search visibility.",stat:"+40% click-through rate"},{icon:<Icons.Megaphone/>,title:"AI Ad Campaign Manager",desc:"Launch and optimize ads across Meta, Google, TikTok, and Shopify with AI-generated creatives.",stat:"4.8x avg ROAS"},{icon:<Icons.Headphones/>,title:"AI Customer Support",desc:"Instant AI-powered ticket resolution with confidence scoring and seamless human handoff.",stat:"< 30s avg response time"},{icon:<Icons.Search/>,title:"Store Audit & Crawling",desc:"Comprehensive website analysis covering SEO, UX, brand voice, content quality, and competitor gaps.",stat:"200+ audit checkpoints"},{icon:<Icons.Lightbulb/>,title:"Smart Recommendations",desc:"Prioritized action items ranked by revenue impact and effort, so you always know what to do next.",stat:"ROI-ranked priorities"},{icon:<Icons.Truck/>,title:"AI Dropshipping Engine",desc:"Connect to vetted suppliers, auto-import winning products, sync inventory in real-time, and automate fulfillment.",stat:"Fully automated fulfillment",badge:"new"}];return(<section id="features" className="section" style={{textAlign:"center"}}><div className="container"><div className="section-label"><Icons.Zap/> Powerful AI Modules</div><h2 className="section-title">Everything You Need to <span className="gradient-text">Scale</span></h2><p className="section-subtitle" style={{marginBottom:60}}>A complete AI-powered toolkit — from autonomous agents and app building to marketing, ads, dropshipping, and growth — designed to run your e-commerce on autopilot.</p><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill, minmax(340px, 1fr))",gap:20}}>{modules.map((m,i)=><div key={i} className="glass-card" style={{padding:28,textAlign:"left"}}><div style={{display:"flex",alignItems:"center",gap:12,marginBottom:14}}><div style={{width:42,height:42,borderRadius:10,background:"rgba(99,102,241,0.1)",display:"flex",alignItems:"center",justifyContent:"center",color:"var(--accent-primary)"}}>{m.icon}</div><h3 style={{fontSize:17,fontWeight:600}}>{m.title}</h3>{m.badge==="new"&&<span className="badge badge-new">New</span>}</div><p style={{fontSize:14,color:"var(--text-secondary)",lineHeight:1.6,marginBottom:16}}>{m.desc}</p><div style={{fontSize:13,fontWeight:600,color:"var(--accent-green)",display:"flex",alignItems:"center",gap:6}}><Icons.TrendingUp/> {m.stat}</div></div>)}</div></div></section>);}

function HowItWorks(){return(<section id="how-it-works" className="section" style={{textAlign:"center"}}><div className="container"><div className="section-label"><Icons.Target/> How EcomRevHub Works</div><h2 className="section-title">Three Simple Steps to <span className="gradient-text">Revenue Growth</span></h2><p className="section-subtitle" style={{marginBottom:60}}>Three simple steps to unlock your store&apos;s full revenue potential.</p><div style={{display:"flex",gap:24,justifyContent:"center",flexWrap:"wrap"}}>{[{n:"1",t:"Enter Your Website",d:"Paste your store URL and let our AI crawl every page, product, and piece of content."},{n:"2",t:"AI Analyzes Everything",d:"Our AI evaluates your SEO, products, brand voice, competitors, and growth opportunities."},{n:"3",t:"Get Your Growth Plan",d:"Receive a step-by-step AI-powered revenue growth roadmap — then watch us execute it."}].map((s,i)=><div key={i} className="glass-card" style={{padding:36,flex:"1 1 300px",maxWidth:360,textAlign:"center"}}><div style={{width:60,height:60,borderRadius:"50%",margin:"0 auto 20px",background:"var(--gradient-primary)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,fontWeight:800,color:"white"}}>{s.n}</div><h3 style={{fontSize:20,fontWeight:600,marginBottom:12}}>{s.t}</h3><p style={{fontSize:15,color:"var(--text-secondary)",lineHeight:1.6}}>{s.d}</p></div>)}</div><div style={{marginTop:40,display:"flex",gap:20,justifyContent:"center",flexWrap:"wrap",alignItems:"center"}}><div style={{padding:"16px 28px",borderRadius:12,background:"rgba(99,102,241,0.06)",border:"1px solid rgba(99,102,241,0.15)",display:"inline-flex",alignItems:"center",gap:12}}><span style={{color:"var(--text-secondary)"}}>Don&apos;t have a store yet?</span><a href="/auth/register" className="btn-primary" style={{padding:"10px 20px",fontSize:14}}><Icons.Code/> Let AI Build It</a></div><div style={{padding:"16px 28px",borderRadius:12,background:"rgba(236,72,153,0.06)",border:"1px solid rgba(236,72,153,0.15)",display:"inline-flex",alignItems:"center",gap:12}}><span style={{color:"var(--text-secondary)"}}>Full Done-For-You Package</span><span style={{fontSize:14,fontWeight:600,color:"#ec4899"}}>Starting at $4,997</span></div></div><div className="glass-card" style={{marginTop:48,padding:28,maxWidth:800,margin:"48px auto 0",textAlign:"left"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20,flexWrap:"wrap",gap:8}}><span style={{fontSize:14,fontWeight:600}}>Watch AI Work</span><span style={{fontSize:12,color:"var(--text-tertiary)",fontFamily:"'Space Mono', monospace"}}>app.ecomrevhub.com/dashboard</span></div><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill, minmax(160px, 1fr))",gap:12}}>{[{l:"Revenue",v:"$48.2K",c:"+12.5%"},{l:"Profit",v:"$18.7K",c:"+8.2%"},{l:"Orders",v:"1,247",c:"+23.1%"},{l:"Conversion",v:"3.8%",c:"+0.4%"}].map((m,i)=><div key={i} style={{padding:16,borderRadius:10,background:"var(--bg-primary)",border:"1px solid var(--border-subtle)"}}><div style={{fontSize:12,color:"var(--text-tertiary)",marginBottom:6}}>{m.l}</div><div style={{fontSize:22,fontWeight:700,fontFamily:"'Space Mono', monospace"}}>{m.v}</div><div style={{fontSize:12,color:"#22c55e",marginTop:4}}>{m.c}</div></div>)}</div></div></div></section>);}

function InteractiveDemo(){const[tab,setTab]=useState(0);const[rev,setRev]=useState(25000);const[plan,setPlan]=useState(1);const mult=[2,3,4];const names=["Starter","Growth","Professional"];const proj=rev*mult[plan];const tabs=["Calculator","Analysis","Stories"];return(<section id="demo" className="section" style={{textAlign:"center"}}><div className="container"><div className="section-label"><Icons.Play/> Interactive Demo</div><h2 className="section-title">See EcomRevHub <span className="gradient-text">In Action</span></h2><p className="section-subtitle" style={{marginBottom:40}}>Explore what our AI can do for your e-commerce business before you even sign up.</p><div style={{display:"flex",justifyContent:"center",gap:4,marginBottom:32}}>{tabs.map((t,i)=><button key={i} onClick={()=>setTab(i)} style={{padding:"10px 24px",borderRadius:8,fontSize:14,fontWeight:500,background:tab===i?"var(--accent-primary)":"var(--bg-tertiary)",color:tab===i?"white":"var(--text-tertiary)",border:"none",cursor:"pointer",fontFamily:"'Sora', sans-serif",transition:"all 0.3s"}}>{t}</button>)}</div><div className="glass-card" style={{maxWidth:700,margin:"0 auto",padding:36,textAlign:"left"}}>{tab===0&&<div><h3 style={{fontSize:20,fontWeight:700,marginBottom:24}}>Revenue Calculator</h3><div style={{marginBottom:24}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:10}}><label style={{fontSize:14,color:"var(--text-secondary)"}}>Current Monthly Revenue</label><span style={{fontSize:14,fontWeight:600,fontFamily:"'Space Mono', monospace",color:"var(--accent-primary)"}}>${rev.toLocaleString()}</span></div><input type="range" min="0" max="100000" step="5000" value={rev} onChange={e=>setRev(+e.target.value)} style={{width:"100%",accentColor:"var(--accent-primary)"}}/><div style={{display:"flex",justifyContent:"space-between",fontSize:11,color:"var(--text-tertiary)",marginTop:4}}><span>$0</span><span>$25K</span><span>$50K</span><span>$75K</span><span>$100K</span></div></div><div style={{marginBottom:24}}><label style={{fontSize:14,color:"var(--text-secondary)",marginBottom:10,display:"block"}}>Select Plan Tier</label><div style={{display:"flex",gap:8}}>{names.map((p,i)=><button key={i} onClick={()=>setPlan(i)} style={{flex:1,padding:"12px 8px",borderRadius:8,fontSize:13,fontWeight:600,background:plan===i?"var(--accent-primary)":"var(--bg-primary)",color:plan===i?"white":"var(--text-secondary)",border:`1px solid ${plan===i?"var(--accent-primary)":"var(--border-subtle)"}`,cursor:"pointer",fontFamily:"'Sora', sans-serif"}}>{p}<br/><span style={{fontSize:11,opacity:0.7}}>{mult[i]}x growth</span></button>)}</div></div><div style={{padding:20,borderRadius:12,background:"var(--bg-primary)",border:"1px solid var(--border-accent)",textAlign:"center"}}><div style={{fontSize:13,color:"var(--text-secondary)",marginBottom:8}}>Projected Monthly Revenue with AI</div><div style={{fontSize:36,fontWeight:800,fontFamily:"'Space Mono', monospace"}} className="gradient-text-green">${proj.toLocaleString()}/mo</div><div style={{fontSize:14,color:"var(--text-tertiary)",marginTop:8}}>That&apos;s a {mult[plan]}x increase with the {names[plan]} plan</div></div><a href="/auth/register" className="btn-primary" style={{width:"100%",justifyContent:"center",marginTop:20}}>Start Growing Now</a></div>}{tab===1&&<div style={{textAlign:"center",padding:"20px 0"}}><h3 style={{fontSize:20,fontWeight:700,marginBottom:16}}>AI Analysis Preview</h3><p style={{color:"var(--text-secondary)",marginBottom:24}}>Enter your store URL to see a live AI analysis preview.</p><div style={{display:"flex",gap:12,marginBottom:20}}><input type="text" placeholder="yourstore.com" style={{flex:1,padding:"14px 18px",borderRadius:10,background:"var(--bg-primary)",border:"1px solid var(--border-default)",color:"var(--text-primary)",fontSize:15,fontFamily:"'Space Mono', monospace",outline:"none"}}/><button className="btn-primary"><Icons.Search/> Analyze</button></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>{[{l:"SEO Score",v:"—/100"},{l:"Page Speed",v:"—s"},{l:"Mobile UX",v:"—/100"},{l:"Cart Recovery",v:"—%"}].map((m,i)=><div key={i} style={{padding:16,borderRadius:10,background:"var(--bg-primary)",border:"1px solid var(--border-subtle)"}}><div style={{fontSize:12,color:"var(--text-tertiary)"}}>{m.l}</div><div style={{fontSize:20,fontWeight:700,fontFamily:"'Space Mono', monospace",marginTop:4}}>{m.v}</div></div>)}</div></div>}{tab===2&&<div><h3 style={{fontSize:20,fontWeight:700,marginBottom:20,textAlign:"center"}}>Success Stories</h3>{[{n:"NovaBrand Co.",r:"$8K → $52K/mo in 2 months",m:"550% growth"},{n:"UrbanThread Apparel",r:"90% of marketing automated",m:"Revenue on autopilot"},{n:"Bloom & Barrel",r:"AOV increased 65%",m:"Product optimization"}].map((s,i)=><div key={i} style={{padding:16,borderRadius:10,background:"var(--bg-primary)",border:"1px solid var(--border-subtle)",marginBottom:12,display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:8}}><div><div style={{fontSize:14,fontWeight:600}}>{s.n}</div><div style={{fontSize:13,color:"var(--text-secondary)"}}>{s.r}</div></div><span style={{fontSize:13,fontWeight:600,color:"var(--accent-green)",padding:"4px 12px",borderRadius:6,background:"rgba(34,197,94,0.1)"}}>{s.m}</span></div>)}</div>}</div></div></section>);}

